{
  "name": "afridoc_mt",
  "full_name": "AFRIDOC-MT: A Document-Level Multi-Parallel Translation Dataset for African Languages",
  "year": 2024,
  "domain": "Document-level machine translation evaluation for African languages",
  "porting_strategy": "ground_up",
  "languages": [
